patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 439a86d951a8..0c7e14a3fa38 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1706,6 +1706,7 @@ static Value *foldOperationIntoSelectOperand(Instruction &I, SelectInst *SI,
   return Clone;
 }

+
 Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
                                                 bool FoldWithMultiUse) {
   // Don't modify shared select instructions unless set FoldWithMultiUse
@@ -1719,6 +1720,54 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
   if (SI->getType()->isIntOrIntVectorTy(1))
     return nullptr;

+  // Recognize:
+  //   %c = fcmp ord X, 0.0
+  //   %s = select %c, X, 0.0
+  //   %r = fcmp oeq %s, K
+  // where K is a non-zero FP constant (scalar or vector).
+  //
+  // This is equivalent to:
+  //   %r = fcmp oeq X, K
+  //
+  // If X is ordered, the select yields X. If X is NaN, the select yields
+  // zero, and comparing zero to a non-zero constant with ordered equality is
+  // false; comparing NaN directly with ordered equality is also false.
+  if (auto *Cmp = dyn_cast<FCmpInst>(&Op)) {
+    if (Cmp->getPredicate() == FCmpInst::FCMP_OEQ) {
+      Value *OtherOp = nullptr;
+      bool SelectIsLHS = false;
+      if (Cmp->getOperand(0) == SI) {
+        OtherOp = Cmp->getOperand(1);
+        SelectIsLHS = true;
+      } else if (Cmp->getOperand(1) == SI) {
+        OtherOp = Cmp->getOperand(0);
+        SelectIsLHS = false;
+      }
+
+      if (OtherOp) {
+        auto *OtherC = dyn_cast<Constant>(OtherOp);
+        auto *FalseC = dyn_cast<Constant>(FV);
+        auto *Cond = dyn_cast<FCmpInst>(SI->getCondition());
+        if (OtherC && FalseC && Cond &&
+            Cond->getPredicate() == FCmpInst::FCMP_ORD &&
+            FalseC->isNullValue() && !OtherC->isNullValue()) {
+          Value *X = nullptr;
+          if (TV == Cond->getOperand(0) && FV == Cond->getOperand(1))
+            X = TV;
+          else if (TV == Cond->getOperand(1) && FV == Cond->getOperand(0))
+            X = TV;
+
+          if (X) {
+            Value *LHS = SelectIsLHS ? X : OtherOp;
+            Value *RHS = SelectIsLHS ? OtherOp : X;
+            return FCmpInst::Create(Instruction::FCmp, Cmp->getPredicate(), LHS,
+                                    RHS);
+          }
+        }
+      }
+    }
+  }
+
   // Test if a FCmpInst instruction is used exclusively by a select as
   // part of a minimum or maximum operation. If so, refrain from doing
   // any other folding. This helps out other analyses which understand
@@ -1749,6 +1798,7 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
   return SelectInst::Create(SI->getCondition(), NewTV, NewFV, "", nullptr, SI);
 }

+
 static Value *simplifyInstructionWithPHI(Instruction &I, PHINode *PN,
                                          Value *InValue, BasicBlock *InBB,
                                          const DataLayout &DL,

